        {id: 2, term: "\u884c\u5c06\u5c31\u6728", definition: "\u5feb\u8981\u8fdb\u68fa\u6750\u4e86\u3002\u6307\u4eba\u4e34\u8fd1\u6b7b\u4ea1\u3002", definitionEn: "About to enter the coffin; approaching death."}
